function candidate(first, second) {
  if (second.generatedLine > first.generatedLine) {
    return true;
  }

  if (second.generatedLine === first.generatedLine && second.generatedColumn >= first.generatedColumn) {
    return true;
  }

  const compare = typeof candidate.compareGenerated === "function"
    ? candidate.compareGenerated
    : defaultGeneratedCompare;

  return compare(first, second) <= 0;
}

function defaultGeneratedCompare(left, right) {
  const leftLine = Number(left.generatedLine);
  const rightLine = Number(right.generatedLine);

  if (leftLine !== rightLine) {
    return leftLine - rightLine;
  }

  const leftColumn = Number(left.generatedColumn);
  const rightColumn = Number(right.generatedColumn);

  if (leftColumn !== rightColumn) {
    return leftColumn - rightColumn;
  }

  return 0;
}
